SET academy_metadata = '{"displayName":"Cyprus – Student Visa (Entry Permit + Pink Slip)","shortDescription":"CRMD Cyprus · VFS India · Entry Permit → Pink Slip within 7 days","version":"v2.0","versionStatus":"Live","reviewStatus":"active","updatedLabel":"Updated 10 Jun 2026","learningLevel":"Intermediate","learningMinutes":24,"policyAlert":{"active":true,"date":"10 Jun 2026","summary":"Cyprus is NOT Schengen — Pink Slip does not allow EU travel. Confirm fees at visa.vfsglobal.com/cyprus/india."},"alert":{"title":"Two-stage visa + NOT Schengen","body":"Entry Permit before travel; Pink Slip within 7–10 days of arrival. Cyprus residence permit does NOT allow Schengen travel without a separate visa. Confirm institution is in South Cyprus (EU), not TRNC."},"tags":[{"label":"Active service","variant":"success"},{"label":"PCC apostille critical","variant":"warning"},{"label":"4–8 weeks","variant":"neutral"},{"label":"VFS appointment","variant":"neutral"},{"label":"NOT Schengen","variant":"warning"}],"chips":[{"label":"4–8 weeks","variant":"neutral"},{"label":"€60–90 Entry Permit","variant":"neutral"},{"label":"Pink Slip 7 days","variant":"warning"},{"label":"NOT Schengen travel","variant":"warning"}],"kpis":[{"label":"Processing time","value":"4–8w","sub":"Entry Permit via VFS India","tone":"primary"},{"label":"Government fee","value":"€60–90","sub":"+ Pink Slip €70–140 after arrival","tone":"warning"},{"label":"Our approval rate","value":"90%","sub":"~78% benchmark","tone":"success"},{"label":"Required docs","value":"18","sub":"+ PCC apostille & medical panel","tone":"violet"},{"label":"Consultancy fee","value":"See fee tab","sub":"+ govt & third-party","tone":"primary"}],"about":[{"label":"Description","value":"Two-stage student immigration: (1) Entry Permit obtained from India via VFS Global or university-assisted CRMD route before travel; (2) Temporary Residence Permit (Pink Slip) at local CRMD within 7–10 days of arrival in Cyprus."},{"label":"Eligible applicants","v