istory"},{"q":"Is Health insurance (travel + statutory) required?","a":"Assess whether Health insurance (travel + statutory) is satisfied for this case."},{"q":"Is Motivation letter and CV required?","a":"Motivation letter and CV is typically required."},{"q":"Is Language proficiency (as required) required?","a":"English per program (IELTS 5.5–6.5 typical; some waive)"},{"q":"Is Valid passport required?","a":"Valid passport is typically required."},{"q":"What is the Processing time?","a":"4–8w — After complete file + PCC apostille"},{"q":"What is the Government fee?","a":"€60–90 — + financial proof €7,000–€10,000+"},{"q":"What is the Our approval rate?","a":"88% — ~74% benchmark"},{"q":"What is the Required docs?","a":"18 — + PCC apostille & medical panel"},{"q":"What is the Consultancy fee?","a":"See fee tab — + govt & third-party"},{"q":"What if the client has PCC apostille not completed?","a":"Start PCC → MEA apostille → Cyprus Embassy attestation immediately; allow 4–6 weeks"},{"q":"Why is PCC apostille not completed a problem?","a":"PCC submitted without MEA apostille or Cyprus Embassy attestation."},{"q":"What if the client has Insufficient financial proof (€7,000–€10,000+)?","a":"Open financial proof (€7,000–€10,000+) at approved bank for full required amount"},{"q":"Why is Insufficient financial proof (€7,000–€10,000+) a problem?","a":"Bank balance below €7,000 or inconsistent 3–6 month history."}],"compliance":["Client service agreement and consent must be on file before submission","Never guarantee visa or immigration approval; use approved-language only","Fee quotes must separate consultancy, government, and third-party costs","Proof of funds funds belong to client—never commingle with firm accounts"],"proTips":["Start PCC process the day offer letter arrives — longest lead item","Book VFS appointment 8–12 weeks before intended travel","Time medical tests for 4-month validity window","Confirm institution at moec.gov.cy — South Cyprus only","Warn clients: 